#!/usr/bin/env bash
set -euo pipefail

CONTEXT="${1:?context json path required}"
OUTPUT_FILE="${2:?output file required}"
MODEL="${3:-composer-2.5}"
TIMEOUT_SECONDS="${4:-900}"

CURRENT_VERSION=$(jq -r .current_version "$CONTEXT")
LAST_TAG=$(jq -r .last_tag "$CONTEXT")
BASE_REF=$(jq -r .base_ref "$CONTEXT")
MIN_BUMP=$(jq -r .min_bump "$CONTEXT")
BUF_BREAKING=$(jq -r .buf_breaking "$CONTEXT")
BUF_OUTPUT=$(jq -r .buf_output "$CONTEXT")

PROMPT_FILE=$(mktemp)
cat > "$PROMPT_FILE" <<PROMPT
You are preparing the next Lightning.Pub release.

The repository is checked out in the current working directory at the commit to analyze.
READ ONLY: inspect the repo with git and file reads. Do not modify files, commit, push, or open pull requests.

CI context:
- current package.json version: ${CURRENT_VERSION}
- last release tag: ${LAST_TAG}
- compare changes since: ${BASE_REF}
- minimum required bump from buf: ${MIN_BUMP}
- buf breaking detected: ${BUF_BREAKING}

buf output:
${BUF_OUTPUT}

What to inspect yourself:
- git log ${BASE_REF}..HEAD --oneline
- git diff ${BASE_REF}..HEAD -- proto/service src/
- proto/service/*.proto for public API changes
- proto/autogenerated/client.md if routes changed

Return ONLY JSON with keys: bump, version, release_notes.
- bump must be patch, minor, or major
- version must be the semver after applying bump to ${CURRENT_VERSION}
- if buf breaking is true, bump must be major
- if methods.proto adds RPCs without breaking changes, bump must be at least minor
- release_notes are for node operators; mention API, config, and migration impact
PROMPT

AGENT_BIN=""
for candidate in \
  "$(command -v agent || true)" \
  "$HOME/.local/bin/agent" \
  "$HOME/.cursor/bin/agent"
do
  if [ -n "$candidate" ] && [ -x "$candidate" ]; then
    AGENT_BIN="$candidate"
    break
  fi
done

if [ -z "$AGENT_BIN" ]; then
  echo "Cursor agent binary not found"
  exit 1
fi

echo "Using agent: ${AGENT_BIN}"
echo "Model: ${MODEL}"

# Prompt via stdin (avoid ARG_MAX). --trust required for headless CI.
# Timeout guards against known agent hang-after-success in GitHub Actions.
set +e
timeout "${TIMEOUT_SECONDS}" "$AGENT_BIN" -p --force --trust \
  --model "$MODEL" \
  --output-format text \
  < "$PROMPT_FILE" > "$OUTPUT_FILE" 2>/tmp/agent-stderr.txt
STATUS=$?
set -e

if [ -s /tmp/agent-stderr.txt ]; then
  echo "=== agent stderr ==="
  cat /tmp/agent-stderr.txt
fi

rm -f "$PROMPT_FILE"

if [ "$STATUS" -eq 124 ]; then
  echo "Cursor agent timed out after ${TIMEOUT_SECONDS}s"
  exit 1
fi

if [ "$STATUS" -ne 0 ]; then
  echo "Cursor agent exited with status ${STATUS}"
  exit "$STATUS"
fi

if [ ! -s "$OUTPUT_FILE" ]; then
  echo "Cursor agent produced empty output"
  exit 1
fi
